app.post('/authorize', (req, res) => {
  const { username, password, client_id, redirect_uri, response_type, scope, state } = req.body;

  if (!response_type || response_type !== 'code') {
    return res.status(400).json({ error: 'invalid_request', error_description: 'response_type must be code' });
  }

  if (!client_id || !redirect_uri) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing required parameters' });
  }

  if (!isValidUrl(redirect_uri)) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'redirect_uri must be a valid URL' });
  }

  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }

  if (!validateRedirectUri(client_id, redirect_uri)) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'redirect_uri not registered' });
  }

  const user = users.get(username);
  if (!user || user.password !== password) {
    const errorUrl = new URL(redirect_uri);
    errorUrl.searchParams.append('error', 'access_denied');
    errorUrl.searchParams.append('error_description', 'Invalid credentials');
    if (state) errorUrl.searchParams.append('state', state);
    return res.redirect(errorUrl.toString());
  }

  const code = generateRandomString();
  const codeData = {
    code,
    clientId: client_id,
    redirectUri: redirect_uri,
    username,
    scope: scope || '',
    expiresAt: Date.now() + 600000
  };

  authorizationCodes.set(code, codeData);

  setTimeout(() => {
    authorizationCodes.delete(code);
  }, 600000);

  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.append('code', code);
  if (state) redirectUrl.searchParams.append('state', state);

  res.redirect(redirectUrl.toString());
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  const authHeader = req.headers.authorization;
  let clientIdAuth = client_id;
  let clientSecretAuth = client_secret;

  if (authHeader && authHeader.startsWith('Basic ')) {
    const base64Credentials = authHeader.slice(6);
    const credentials = Buffer.from(base64Credentials, 'base64').toString('utf-8');
    const [id, secret] = credentials.split(':');
    clientIdAuth = id;
    clientSecretAuth = secret;
  }

  if (!grant_type || grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }

  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'code is required' });
  }

  if (!clientIdAuth || !clientSecretAuth) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'client credentials required' });
  }

  const client = clients.get(clientIdAuth);
  if (!client || client.clientSecret !== clientSecretAuth) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const codeData = authorizationCodes.get(code);
  if (!codeData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid or expired authorization code' });
  }

  if (codeData.expiresAt < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
  }

  if (codeData.clientId !== clientIdAuth) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code was issued to another client' });
  }

  if (redirect_uri && codeData.redirectUri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'redirect_uri mismatch' });
  }

  authorizationCodes.delete(code);

  const accessToken = generateRandomString();
  const refreshToken = generateRandomString();

  const tokenData = {
    accessToken,
    refreshToken,
    clientId: clientIdAuth,
    username: codeData.username,
    scope: codeData.scope,
    expiresAt: Date.now() + 3600000
  };

  accessTokens.set(accessToken, tokenData);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken,
    scope: codeData.scope
  });
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  if (tokenData.expiresAt < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token expired' });
  }

  res.json({
    sub: tokenData.username,
    username: tokenData.username
  });
});

function escapeHtml(text) {
  if (!text) return '';
  const map = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  };
  return text.toString().replace(/[&<>"']/g, m => map[m]);
}

